logger = logging.getLogger(__name__)

class ModelLoader:
    def __init__(self):
        self.model = None
        self.bucket_name = None
        self.base_prefix = None
        self._s3_client = boto3.client('s3')
        self._load_model_on_startup()

    def _parse_s3_path(self, s3_path):
        if not s3_path.startswith("s3://"):
            raise ValueError("S3 path must start with 's3://'")
        parsed_url = urlparse(s3_path)
        self.bucket_name = parsed_url.netloc
        self.base_prefix = parsed_url.path.lstrip('/')
        if not self.bucket_name or not self.base_prefix:
            raise ValueError("Invalid S3 path format. Expected s3://bucket-name/path/to/models")

    def _find_latest_model_key(self):
        response = self._s3_client.list_objects_v2(
            Bucket=self.bucket_name,
            Prefix=self.base_prefix + '/',
            Delimiter='/'
        )

        version_prefixes = []
        if 'CommonPrefixes' in response:
            for common_prefix_obj in response['CommonPrefixes']:
                prefix = common_prefix_obj['Prefix']
                version_part = prefix[len(self.base_prefix) + 1:].strip('/')
                if version_part:
                    version_prefixes.append(version_part)
        
        if not version_prefixes:
            logger.warning(f"No versioned directories found under s3://{self.bucket_name}/{self.base_prefix}")
            return None

        latest_version = sorted(version_prefixes, reverse=True)[0]

        latest_version_prefix = f"{self.base_prefix}/{latest_version}/"
        version_response = self._s3_client.list_objects_v2(
            Bucket=self.bucket_name,
            Prefix=latest_version_prefix
        )

        model_key = None
        model_filename = "model.pkl" 

        if 'Contents' in version_response:
            for obj in version_response['Contents']:
                if obj['Key'].endswith(f'/{model_filename}'):
                    model_key = obj['Key']
                    break
        
        if model_key is None:
            logger.warning(f"No '{model_filename}' found in the latest version directory: s3://{self.bucket_name}/{latest_version_prefix}")
            return None

        logger.info(f"Identified latest model key: s3://{self.bucket_name}/{model_key}")
        return model_key

    def _download_and_load_model(self, model_key):
        try:
            logger.info(f"Downloading model from s3://{self.bucket_name}/{model_key}")
            obj = self._s3_client.get_object(Bucket=self.bucket_name, Key=model_key)
            model_data = obj['Body'].read()
            self.model = pickle.loads(model_data)
            logger.info("Model loaded successfully.")
        except ClientError as e:
            logger.error(f"Error downloading model from S3: {e}")
            raise
        except pickle.PickleError as e:
            logger.error(f"Error unpickling model: {e}")
            raise
        except Exception as e:
            logger.error(f"An unexpected error occurred during model download/load: {e}")
            raise

    def _load_model_on_startup(self):
        s3_path_env = os.environ.get("MODEL_S3_PATH")
        if not s3_path_env:
            raise EnvironmentError("Environment variable 'MODEL_S3_PATH' is not set.")

        self._parse_s3_path(s3_path_env)
        logger.info(f"Configured S3 path: {s3_path_env}")

        latest_key = self._find_latest_model_key()
        if latest_key:
            self._download_and_load_model(latest_key)
        else:
            raise RuntimeError("Could not find a suitable model to load.")

    def get_model(self):
        if self.model is None:
            raise RuntimeError("Model has not been loaded.")
        return self.model

